failure.message:
AssertionError: Missing /api/solutions in cache patterns assert '/api/solutions' in "// LEXA Service Worker v3 â€” Enhanced Caching Strategy
// Cache-first for static assets, stale-while-revalidate for API, offline fallback

const STATIC_CACHE = 'lexa-static-v3';
const API_CACHE = 'lexa-api-v1';
const API_MAX_AGE_MS = 5 * 60 * 1000; // 5 minutes TTL for API cache

// Patterns to cache on fetch (static assets)
const STATIC_PATTERNS = [
 /\/_next\/static\/.*/, // Next.js hashed chunks (immutable)
 /\/_next\/image\?.*/, // Next.js optimized images
 /\.woff2$/,
 /\.woff$/,
 /\.css$/,
 /\.png$/,
 /\.jpg$/,
 /\.jpeg$/,
 /\.webp$/,
 /\.svg$/,
 /\.ico$/,
];

// API patterns to cache with stale-while-revalidate
const API_CACHE_PATTERNS = [
 /\/api\/solutions/,
 /\/api\/projects/,
 /\/api\/articles/,
 /\/api\/services/,
 /\/api\/brands/,
 /\/api\/packages/,
 /\/api\/testimonials/,
 /\/api\/locations/,
 /\/api\/settings/,
];

// Never cache these
const NEVER_CACHE = [
 /\/api\/admin/,
 /\/api\/auth/,
 /\/api\/bookings/,
 /\/api\/submissions/,
 /\/api\/analytics/,
 /\/api\/clear-cache/,
 /google-analytics/,
 /googletagmanager/,
 /facebook/,
 ...d not expired, return immediately
 if (cached) {
 const cachedAt = parseInt(cached.headers.get('sw-cached-at') || '0');
 const age = Date.now() - cachedAt;
 if (age < API_MAX_AGE_MS) {
 // Fresh enough â€” return cached, update in background
 fetchPromise; // fire-and-forget background update
 return cached;
 }
 }

 // No valid cache â€” wait for network
 const networkResponse = await fetchPromise;
 if (networkResponse) return networkResponse;
 // Network failed, return stale cache as fallback
 if (cached) return cached;
 return new Response(JSON.stringify({ error: 'offline' }), {
 status: 503,
 headers: { 'Content-Type': 'application/json' },
 });
 })
 );
 return;
 }
});

// Message handler for cache control
self.addEventListener('message', (event) => {
 if (event.data === 'skipWaiting') self.skipWaiting();
 if (event.data === 'clearCache') {
 caches.delete(STATIC_CACHE);
 caches.delete(API_CACHE);
 }
 if (event.data === 'clearAPICache') {
 caches.delete(API_CACHE);
 }
});
"

